import React from 'react'
import ReactMarkdown from 'react-markdown'

import { Layout } from '../layout'
import { ExperienceProps } from '../../interface'

import './style.css'

export class Experience extends React.Component<ExperienceProps> {
  render() {
    return (
      <Layout title={this.props.title}>
        {this.renderBody()}
      </Layout>
    )
  }

  private renderBody() {
    const bodys = this.props.companies
      .map((data, i) => {
        return (
          <div key={i}>
            <div className="resume-experience-header">
              <span className="resume-experience-company">{data.name}</span>
              <span className="resume-experience-work-title">{data.title}</span>
              <span className="resume-experience-work-time">{data.time}</span>
            </div>
            <div className="resume-experience-content">
              <ReactMarkdown source={data.content || ''} />
            </div>
          </div>
        )
      })
    return (
      <div>
        {bodys}
      </div>
    )
  }
}



