import * as React from 'react';

import Resume from './views/resume'

import { Lang } from './lang'

interface AppProps {
  lang: Lang
}

class App extends React.Component<AppProps> {
  render() {
    return (
      <div className="App">
        <Resume lang={this.props.lang} />
      </div>
    );
  }
}

export default App;



