import * as React from 'react';

import { base, experience, skill } from '../../config'
import { Base } from '../../components/base'
import { Experience } from '../../components/experience'
import { Skill } from '../../components/skills'

import { Lang } from '../../lang'
import './style.css'

interface AppProps {
    lang: Lang
}

class Resume extends React.Component<AppProps> {
    render() {
        const _headerProps = base.zh
        const _experienceProps = experience.zh
        const _skillProps = skill.zh
        return (
            <div className="resume">
                <header className="resume-header">
                    <h2>简历</h2>
                </header>
                <Base { ..._headerProps } />
                <Experience { ..._experienceProps } />
                <Skill { ..._skillProps } />
            </div>
        );
    }
}

export default Resume;



