import React from 'react'
import './style.css'

export interface LayoutProps {
    title: string
}

export class Layout extends React.Component<LayoutProps>{
    render() {
        return (
            <div className="resume-layout">
                <div className="resume-layout-title">{this.props.title}</div>
                <hr/>
                <div className="resume-layout-content">
                    {this.props.children}
                </div>
            </div>
        )
    }
}



