import React from 'react'
import './style.css'

import { BaseProps } from '../../interface'

import { Layout } from '../layout'

export class Base extends React.Component<BaseProps> {
  render() {
    return (
      <Layout title={this.props.title}>
        <div className="resume-base">
          <div className="resume-base-container">
            <div className="resume-base-info">
              <span>Name: </span>
              <span className="resume-base-info-content">{this.props.name}</span>
            </div>
            <div className="resume-base-info">
              <span>Sex: </span>
              <span className="resume-base-info-content">{this.props.sex}</span>
            </div>
            <div className="resume-base-info">
              <span>Education: </span>
              <span className="resume-base-info-content">{this.props.education}</span>
            </div>
            <div className="resume-base-info">
              <span>E-mail: </span>
              <a className="resume-base-info-content"
                href="mailto:82565097@qq.com"
              >
                {this.props.email}
              </a>
            </div>
            <div className="resume-base-info">
              <span>Site: </span>
              <a className="resume-base-info-content"
                href={this.props.site}
                target="_blank">
                {this.props.site}
              </a>
            </div>
            <div className="resume-base-info">
              <span>Github: </span>
              <a className="resume-base-info-content"
                href={this.props.github.url}
                target="_blank">
                {this.props.github.name}
              </a>
            </div>
            <div className="resume-base-info">
              <span>Zhihu: </span>
              <a className="resume-base-info-content"
                href={this.props.zhihu.url}
                target="_blank">
                {this.props.zhihu.name}
              </a>
            </div>
          </div>
        </div>
      </Layout>
    )
  }
}



